// ═══════════════════════════════════════════════════════════
// MÓDULOS Y QUIZZES — CURSOS PROCADIST PARTE 2 (FALTANTES)
// Cursos que no estaban en Part 1
// 4 módulos + quiz por curso | Máximo 1 hora cada uno
// ═══════════════════════════════════════════════════════════

export const procadistModulesPart2: Record<string, any[]> = {

// ═══ 1. NOM-031 CONSTRUCCIÓN ═══
"nom-031-construccion": [
  { title: "Marco Normativo y Riesgos en Construcción", description: "NOM-031-STPS-2011, estadísticas de accidentes y obligaciones", contentHtml: `<h2>El sector más peligroso</h2><p>La construcción es uno de los sectores con mayor índice de accidentes mortales en México. La NOM-031-STPS-2011 establece las condiciones de seguridad e higiene en actividades de construcción.</p><h3>Principales riesgos</h3><ul><li><strong>Caídas de altura:</strong> #1 causa de muerte en construcción</li><li><strong>Derrumbes y sepultamientos:</strong> Excavaciones, zanjas, demoliciones</li><li><strong>Golpes por objetos:</strong> Caída de materiales, herramientas, escombros</li><li><strong>Electrocución:</strong> Contacto con líneas eléctricas, instalaciones provisionales</li><li><strong>Atrapamiento:</strong> Maquinaria, estructuras colapsadas</li></ul><h3>Obligaciones del patrón</h3><ul><li>Análisis de riesgos específico por obra</li><li>Plan de seguridad y salud para la obra</li><li>Capacitación a todo el personal antes de iniciar labores</li><li>EPP específico: casco, arnés (alturas), calzado de seguridad, lentes, chaleco</li><li>Señalización perimetral y de zonas de riesgo</li><li>Instalaciones sanitarias adecuadas</li></ul>`, references: ["NOM-031-STPS-2011", "NOM-009-STPS-2011 (Alturas)", "IMSS - Estadísticas de riesgos de trabajo"], durationMinutes: 15 },
  { title: "Excavaciones, Cimentaciones y Trabajos Estructurales", description: "Seguridad en excavaciones, zanjas, cimentaciones y trabajo con concreto", contentHtml: `<h2>Lo que no se ve puede matar</h2><h3>Excavaciones y zanjas</h3><ul><li>Toda excavación mayor a 1.5m de profundidad requiere sistema de protección contra derrumbe: <strong>talud</strong> (inclinación de paredes), <strong>ademe</strong> (soporte de paredes), o <strong>escudo de zanja</strong></li><li>Verificar ausencia de instalaciones subterráneas (gas, electricidad, agua, drenaje) antes de excavar</li><li>Mantener el material excavado a mínimo 60cm del borde</li><li>Escalera de acceso a máximo 7.5m de cualquier punto de la excavación</li><li>No entrar a zanjas sin verificar que no hay acumulación de gases</li></ul><h3>Cimentaciones</h3><ul><li>Verificar estabilidad del terreno</li><li>Cimbra asegurada y verificada antes de colar</li><li>Protección contra caída en bordes de losas</li></ul><h3>Trabajo con concreto</h3><ul><li>El concreto fresco es alcalino — quema la piel con exposición prolongada</li><li>EPP: guantes impermeables, botas de hule, lentes</li><li>Nunca caminar sobre cimbra sin verificar que soporta el peso</li></ul>`, references: ["NOM-031-STPS-2011 Cap. 10 y 11", "OSHA - Excavation Safety", "CFE - Consulta de instalaciones subterráneas"], durationMinutes: 15 },
  { title: "Trabajos en Altura y Uso de Andamios en Obra", description: "Protección contra caídas, andamios, escaleras y plataformas en construcción", contentHtml: `<h2>El arnés es tu seguro de vida</h2><h3>Protección contra caídas en obra</h3><ul><li>Obligatoria a partir de <strong>1.80 metros</strong> de altura</li><li>Barandales perimetrales en bordes de losa, huecos, aberturas</li><li>Redes de seguridad donde sea factible</li><li>Arnés de cuerpo completo + línea de vida anclada a punto certificado</li><li>Cubrir o señalizar TODOS los huecos en pisos (registros, ductos, escaleras)</li></ul><h3>Andamios en construcción</h3><ul><li>Armados sobre superficie firme y nivelada</li><li>Plataformas completas con barandal, rodapié y barrera intermedia</li><li>Nunca usar andamios como soporte de carga de materiales pesados (a menos que estén diseñados para eso)</li><li>Inspección diaria antes de usar</li><li>Distancia mínima de 3m de líneas eléctricas</li></ul><h3>Escaleras de obra</h3><ul><li>Regla 4:1, asegurada arriba y abajo</li><li>No usar como puente entre estructuras</li><li>Escaleras metálicas lejos de instalaciones eléctricas</li></ul>`, references: ["NOM-031-STPS-2011 Cap. 9", "NOM-009-STPS-2011", "OSHA - Fall Protection in Construction"], durationMinutes: 15 },
  { title: "Instalaciones Eléctricas, Demolición y Plan de Seguridad", description: "Electricidad provisional, demoliciones seguras y programa de seguridad de obra", contentHtml: `<h2>Cada obra necesita su plan</h2><h3>Instalaciones eléctricas provisionales</h3><ul><li>Tableros con protección diferencial (interruptor de falla a tierra)</li><li>Cables protegidos contra daño mecánico y agua</li><li>Conexiones a tierra en todos los equipos</li><li>Solo personal calificado realiza conexiones</li><li>No usar extensiones dañadas ni empalmes improvisados</li></ul><h3>Demoliciones</h3><ul><li>Requieren plan específico de demolición elaborado por especialista</li><li>Desconectar TODAS las instalaciones (gas, electricidad, agua) antes de iniciar</li><li>Perímetro de seguridad señalizado y vigilado</li><li>Secuencia de demolición que evite colapso no controlado</li><li>Control de polvo (riego con agua) y manejo de escombros</li></ul><h3>Plan de seguridad de la obra</h3><p>Toda obra debe tener un documento que incluya:</p><ul><li>Análisis de riesgos específicos de esa obra</li><li>Medidas de prevención y control para cada riesgo</li><li>EPP requerido por actividad</li><li>Procedimientos de emergencia</li><li>Programa de capacitación antes de iniciar</li><li>Responsable de seguridad designado</li></ul>`, references: ["NOM-031-STPS-2011 Cap. 7, 12 y 14", "NOM-029-STPS-2011 (Electricidad)", "Reglamento de Construcciones"], durationMinutes: 15 }
],

// ═══ 2. NOM-017 EPP (versión PROCADIST) ═══
"nom-017-epp-procadist": [
  { title: "Fundamentos de la NOM-017 y Selección de EPP", description: "Objetivo, obligaciones y tabla de selección de EPP por riesgo", contentHtml: `<h2>La norma del equipo de protección</h2><p>La NOM-017-STPS-2008 establece los requisitos para seleccionar, usar y manejar el EPP en los centros de trabajo. El EPP es la <strong>última línea de defensa</strong> — se usa cuando los demás controles no eliminan completamente el riesgo.</p><h3>Principio fundamental</h3><p>La selección NO es por intuición ni por catálogo. Se basa en un <strong>análisis de riesgos por puesto de trabajo</strong> que cruza: zona del cuerpo × tipo de riesgo × nivel de exposición.</p><h3>Clasificación por zona</h3><ul><li><strong>Cabeza:</strong> Cascos clase E (eléctrico), G (general)</li><li><strong>Ojos/cara:</strong> Lentes, goggles, caretas</li><li><strong>Oídos:</strong> Tapones, orejeras (cuando ruido >85 dB)</li><li><strong>Respiratorio:</strong> Mascarillas, respiradores con cartucho, SCBA</li><li><strong>Manos:</strong> Guantes específicos por riesgo (químico, mecánico, eléctrico, térmico)</li><li><strong>Pies:</strong> Calzado con casquillo, dieléctrico, antiderrapante</li><li><strong>Cuerpo:</strong> Mandiles, arneses, ropa de alta visibilidad</li></ul><h3>Obligación del patrón</h3><p>Proporcionar EPP <strong>sin costo</strong>, capacitar en su uso, supervisar que se use, y reemplazar cuando se dañe.</p>`, references: ["NOM-017-STPS-2008", "ANSI Z87.1", "OSHA - PPE Standards"], durationMinutes: 15 },
  { title: "Uso, Inspección y Mantenimiento", description: "Procedimientos de colocación, inspección previa y mantenimiento del EPP", contentHtml: `<h2>EPP sin mantenimiento = falsa protección</h2><h3>Antes de CADA uso</h3><ol><li>Inspeccionar visualmente: ¿grietas, desgaste, perforaciones?</li><li>Verificar talla y ajuste correcto</li><li>Colocar según instrucciones del fabricante</li><li>En respiradores: prueba de sello (presión positiva y negativa)</li></ol><h3>Mantenimiento por tipo</h3><ul><li><strong>Cascos:</strong> Lavar con agua y jabón. Reemplazar al primer golpe fuerte o según vida útil (2-5 años)</li><li><strong>Lentes:</strong> Limpiar con paño suave. Reemplazar si hay rayones que afecten visibilidad</li><li><strong>Respiradores:</strong> Cambiar filtros según indicación. Limpiar pieza facial regularmente</li><li><strong>Guantes:</strong> Inspeccionar antes de cada uso. Reemplazar al primer signo de degradación</li><li><strong>Arnés:</strong> Inspeccionar costuras, hebillas, cintas. Retirar de servicio después de detener una caída</li></ul><h3>Almacenamiento</h3><p>Lugar limpio, seco, ventilado. Lejos de luz solar directa y químicos. Cada trabajador con su propio EPP — no se comparte.</p>`, references: ["NOM-017-STPS-2008", "ANSI/ISEA 105", "Fabricantes - Manuales de uso"], durationMinutes: 15 },
  { title: "EPP para Riesgos Específicos", description: "Selección detallada para riesgos químicos, eléctricos, mecánicos y térmicos", contentHtml: `<h2>Cada riesgo tiene su protección</h2><h3>Riesgo químico</h3><ul><li>Guantes: consultar tabla de resistencia química del fabricante. Nitrilo para solventes, butilo para ácidos, etc.</li><li>Respirador: tipo de cartucho según el contaminante (vapores orgánicos, ácidos, polvos)</li><li>Goggles antisalpicadura (sellados)</li><li>Mandil o traje completo según nivel de exposición</li></ul><h3>Riesgo eléctrico</h3><ul><li>Guantes dieléctricos clasificados por voltaje (clase 00 a 4)</li><li>Calzado dieléctrico</li><li>Casco clase E</li><li>Herramientas aisladas hasta 1000V</li></ul><h3>Riesgo mecánico</h3><ul><li>Guantes anticorte (nivel A2-A9 según ANSI)</li><li>Lentes de seguridad contra impacto</li><li>Calzado con casquillo (acero o composite)</li></ul><h3>Riesgo térmico</h3><ul><li>Guantes para calor: cuero, kevlar, aluminio</li><li>Mandil térmico</li><li>Careta para radiación (soldadura: sombra 10-13)</li></ul><h3>Error fatal</h3><p>EPP inadecuado da <strong>falsa sensación de seguridad</strong>. Guantes de látex NO protegen de cortes. Un casco de obra NO protege de electricidad si no es clase E. Selecciona con base en evidencia, no en costumbre.</p>`, references: ["NOM-017-STPS-2008 - Tabla A1", "ANSI Z87.1 (Ojos)", "ASTM F2413 (Calzado)"], durationMinutes: 15 },
  { title: "Programa de EPP y Cumplimiento", description: "Diseño del programa, registros, capacitación y verificación STPS", contentHtml: `<h2>Sistema, no improvisación</h2><h3>Programa de EPP en 6 pasos</h3><ol><li><strong>Análisis de riesgos:</strong> Por puesto de trabajo, documentado</li><li><strong>Selección:</strong> EPP certificado, específico al riesgo identificado</li><li><strong>Adquisición:</strong> Con especificaciones técnicas (no "el más barato")</li><li><strong>Entrega:</strong> Personalizada con registro y firma del trabajador</li><li><strong>Capacitación:</strong> Uso correcto, mantenimiento, limitaciones. Documentar con DC-3</li><li><strong>Supervisión y reemplazo:</strong> Verificar uso diario, reemplazar EPP dañado</li></ol><h3>Registros necesarios</h3><ul><li>Análisis de riesgos por puesto</li><li>Tabla de asignación de EPP por puesto</li><li>Constancias de entrega (firma del trabajador)</li><li>Constancias de capacitación (DC-3)</li><li>Bitácora de inspección y reemplazo</li></ul><h3>Consecuencias del incumplimiento</h3><p><strong>Para el patrón:</strong> Multas de 250 a 5,000 UMAs si no proporciona EPP. <strong>Para el trabajador:</strong> La negativa a usar EPP proporcionado puede ser causa de rescisión (LFT Art. 47, fracc. XII).</p><h3>Ejercicio</h3><p>Selecciona 3 puestos de tu centro de trabajo. Para cada uno: identifica los riesgos, define el EPP requerido, y verifica si actualmente se proporciona y usa correctamente.</p>`, references: ["NOM-017-STPS-2008", "LFT Art. 47 y 132", "STPS - Criterios de verificación"], durationMinutes: 15 }
],

// ═══ 3. NOM-019 COMISIONES (versión PROCADIST) ═══
"nom-019-comisiones-procadist": [
  { title: "Fundamento Legal y Constitución de la CSH", description: "NOM-019, obligación legal, integración bipartita y registro", contentHtml: `<h2>Obligatoria para TODOS</h2><p>La Comisión de Seguridad e Higiene (CSH) es obligatoria para <strong>todo centro de trabajo en México</strong>, sin importar tamaño ni giro. La NOM-019-STPS-2011 establece cómo constituirla y operarla.</p><h3>Integración</h3><ul><li>Igual número de representantes del <strong>patrón</strong> y de los <strong>trabajadores</strong></li><li>Los de trabajadores son elegidos <strong>democráticamente</strong></li><li>Se recomienda que conozcan el proceso productivo</li><li>Mínimo 1 representante por cada parte</li></ul><h3>Funciones principales</h3><ul><li>Recorridos de verificación (mínimo trimestrales)</li><li>Identificar condiciones peligrosas y actos inseguros</li><li>Investigar accidentes de trabajo</li><li>Proponer medidas preventivas y correctivas</li><li>Dar seguimiento a las acciones implementadas</li></ul>`, references: ["NOM-019-STPS-2011", "LFT Art. 509-510", "NOM-030-STPS-2009"], durationMinutes: 15 },
  { title: "Recorridos de Verificación", description: "Planificación, ejecución y documentación de recorridos de seguridad", contentHtml: `<h2>El recorrido es la actividad principal</h2><h3>Cómo hacer un buen recorrido</h3><ol><li><strong>Planificar:</strong> Fecha, hora, área, participantes</li><li><strong>Ejecutar:</strong> Recorrer observando condiciones y conductas</li><li><strong>Documentar:</strong> Hallazgos, ubicación, evidencia fotográfica</li><li><strong>Clasificar:</strong> Priorizar por nivel de riesgo (alto/medio/bajo)</li><li><strong>Recomendar:</strong> Acciones correctivas con responsable y plazo</li><li><strong>Seguimiento:</strong> Verificar implementación en el siguiente recorrido</li></ol><h3>Qué observar</h3><ul><li>Orden y limpieza general</li><li>Estado de pisos, techos, paredes, escaleras</li><li>Señalización correcta y visible</li><li>Extintores en condiciones</li><li>EPP usado correctamente</li><li>Rutas de evacuación despejadas</li><li>Maquinaria con guardas de seguridad</li><li>Instalaciones eléctricas en buen estado</li></ul><h3>Frecuencia</h3><p>Mínimo trimestral (cada 3 meses). Mensual en actividades de alto riesgo. Rotar las áreas para cubrir todo el centro en el año.</p>`, references: ["NOM-019-STPS-2011", "STPS - Guía de recorridos", "NOM-026-STPS-2008"], durationMinutes: 15 },
  { title: "Actas, Seguimiento y Programa Anual", description: "Formato de actas, sistema de seguimiento e indicadores", contentHtml: `<h2>Si no está documentado, no existe</h2><h3>Acta de verificación</h3><p>Debe contener: fecha y hora, área recorrida, participantes, hallazgos con descripción y clasificación, acciones recomendadas con responsable y fecha, y firmas de todos.</p><h3>Sistema de seguimiento</h3><ul><li>Control de hallazgos pendientes vs. cerrados</li><li>% de acciones implementadas a tiempo</li><li>Tendencia de hallazgos por recorrido</li><li>Escalamiento de acciones vencidas</li></ul><h3>Programa anual</h3><p>Al inicio de cada año elaborar: calendario de recorridos (trimestrales mínimo), áreas a cubrir en cada uno, temas de capacitación para los miembros de la CSH, y calendario de reuniones mensuales.</p><h3>Reuniones de la CSH</h3><p>Al menos mensualmente para: revisar actas pendientes, dar seguimiento a acciones, analizar accidentes ocurridos, y planificar próximos recorridos.</p>`, references: ["NOM-019-STPS-2011", "STPS - Formato de actas", "NOM-030-STPS-2009"], durationMinutes: 15 },
  { title: "Investigación de Accidentes y Vinculación con NOMs", description: "Rol de la CSH en investigación de accidentes y conexión con el sistema de gestión", contentHtml: `<h2>La CSH investiga para prevenir</h2><h3>Investigación de accidentes</h3><p>Cuando ocurre un accidente, la CSH debe:</p><ol><li>Acudir al lugar de los hechos</li><li>Recopilar información: entrevistas, fotos, condiciones</li><li>Analizar causas inmediatas Y causas raíz</li><li>Documentar en acta especial</li><li>Proponer acciones correctivas</li><li>Dar seguimiento a la implementación</li></ol><h3>Vinculación con otras NOMs</h3><ul><li><strong>NOM-030:</strong> La CSH es parte del sistema de servicios preventivos</li><li><strong>NOM-035:</strong> Puede detectar factores de riesgo psicosocial</li><li><strong>NOM-017:</strong> Verifica uso correcto de EPP</li><li><strong>NOM-002:</strong> Verifica condiciones contra incendio</li><li><strong>NOM-026:</strong> Evalúa señalización</li></ul><h3>Capacitación de miembros</h3><p>Los integrantes de la CSH deben capacitarse en: normatividad aplicable, técnicas de identificación de riesgos, investigación de accidentes, y primeros auxilios. Esta capacitación genera DC-3.</p><h3>Ejercicio</h3><p>¿Existe CSH en tu centro de trabajo? ¿Está activa? ¿Realiza recorridos documentados? ¿Hay seguimiento a hallazgos? Si no, hay una brecha legal y de seguridad que atender de inmediato.</p>`, references: ["NOM-019-STPS-2011", "NOM-030-STPS-2009", "LFT Art. 509"], durationMinutes: 15 }
],

// ═══ 4. TRABAJO INFANTIL Y DERECHOS DE NNA ═══
"trabajo-infantil-derechos-nna": [
  { title: "Marco Legal: Protección de la Niñez Trabajadora", description: "Constitución, LFT y convenios internacionales sobre trabajo infantil", contentHtml: `<h2>Los niños no deben trabajar — deben aprender y jugar</h2><p>México prohíbe el trabajo de menores de 15 años. Para adolescentes de 15-17, se permite con condiciones estrictas de protección.</p><h3>Marco legal</h3><ul><li><strong>Constitución Art. 123:</strong> Queda prohibida la utilización del trabajo de menores de 15 años</li><li><strong>LFT Art. 22-23:</strong> Edad mínima de admisión: 15 años. Menores de 18 requieren autorización</li><li><strong>LFT Art. 175-180:</strong> Condiciones especiales para adolescentes trabajadores</li><li><strong>OIT Convenio 138:</strong> Edad mínima de admisión al empleo</li><li><strong>OIT Convenio 182:</strong> Peores formas de trabajo infantil</li><li><strong>Ley General de Derechos de NNA:</strong> Protección integral</li></ul><h3>Trabajo infantil en México</h3><p>Según INEGI, millones de niños y adolescentes trabajan en México, muchos en condiciones peligrosas: agricultura, manufactura, comercio informal, trabajo doméstico. La pobreza es la causa principal, pero no la justifica.</p>`, references: ["LFT Art. 22, 23, 175-180", "OIT Convenios 138 y 182", "Ley General de Derechos de NNA"], durationMinutes: 15 },
  { title: "Condiciones de Trabajo para Adolescentes (15-17)", description: "Derechos y protecciones especiales para adolescentes trabajadores", contentHtml: `<h2>Si trabajan, que sea con protección total</h2><h3>Condiciones obligatorias (LFT)</h3><ul><li><strong>Jornada máxima:</strong> 6 horas diarias, con descanso de 30 min</li><li><strong>Horario:</strong> Prohibido trabajo nocturno (después de las 22:00)</li><li><strong>Actividades prohibidas:</strong> Labores peligrosas o insalubres, minas, expendios de bebidas, trabajos superiores a sus fuerzas</li><li><strong>Examen médico:</strong> Obligatorio al inicio y periódicamente</li><li><strong>Seguridad social:</strong> IMSS obligatorio</li><li><strong>Educación:</strong> El patrón debe facilitar que continúen estudiando</li><li><strong>Vacaciones:</strong> 18 días al año (más que adultos)</li></ul><h3>Documentación requerida</h3><ul><li>Acta de nacimiento (verificar edad)</li><li>Autorización de padres o tutores</li><li>Constancia de estudios</li><li>Certificado médico de aptitud</li><li>Contrato escrito con condiciones especiales</li></ul><h3>Sanciones</h3><p>El patrón que emplee menores de 15 años o que incumpla las condiciones especiales para adolescentes enfrenta multas de 250 a 5,000 UMAs y posible acción penal.</p>`, references: ["LFT Art. 175-180", "NOM-031-STPS-2011", "Reglamento Federal de SST"], durationMinutes: 15 },
  { title: "Peores Formas de Trabajo Infantil", description: "Identificación, prevención y denuncia de explotación infantil", contentHtml: `<h2>Tolerancia cero</h2><h3>Peores formas según OIT Convenio 182</h3><ul><li><strong>Esclavitud y trabajo forzoso:</strong> Incluye trata de personas</li><li><strong>Explotación sexual comercial:</strong> Prostitución, pornografía</li><li><strong>Actividades ilícitas:</strong> Narcotráfico, contrabando</li><li><strong>Trabajo peligroso:</strong> Que dañe salud, seguridad o moralidad del menor</li></ul><h3>Trabajos peligrosos en México (LFT Art. 176)</h3><p>Incluyen: exposición a sustancias tóxicas, ruido excesivo, radiaciones, temperaturas extremas, maquinaria peligrosa, trabajo en altura, minas, cantinas, trabajo submarino, y cualquier actividad que afecte el desarrollo psicológico.</p><h3>Señales de alerta</h3><ul><li>Menores realizando actividades de alto riesgo</li><li>Ausencia escolar prolongada</li><li>Signos de maltrato, desnutrición o fatiga extrema</li><li>Jornadas excesivas o trabajo nocturno</li><li>Menores sin registro ante IMSS</li></ul><h3>¿Qué hacer?</h3><p>Si detectas trabajo infantil ilegal: denunciar a la STPS (inspección laboral), DIF, SIPINNA, Procuraduría de Protección de NNA, o PROFEDET. La denuncia puede ser anónima.</p>`, references: ["OIT Convenio 182", "LFT Art. 176", "SIPINNA - Sistema de Protección Integral"], durationMinutes: 15 },
  { title: "Prevención y Corresponsabilidad", description: "Rol de empresas, gobierno y sociedad en la erradicación del trabajo infantil", contentHtml: `<h2>Es responsabilidad de todos</h2><h3>Responsabilidad de la empresa</h3><ul><li>Verificar la edad de todo trabajador al contratar</li><li>Cumplir estrictamente las condiciones especiales para 15-17 años</li><li>No subcontratar servicios donde se empleen menores ilegalmente</li><li>Revisar cadena de proveedores para detectar trabajo infantil</li></ul><h3>Responsabilidad del gobierno</h3><ul><li>Inspecciones laborales efectivas</li><li>Programas sociales que ataquen las causas (pobreza, falta de acceso a educación)</li><li>Becas y apoyos para que los niños permanezcan en la escuela</li></ul><h3>Responsabilidad de la sociedad</h3><ul><li>No normalizar que "los niños ayuden" en condiciones peligrosas</li><li>Denunciar cuando se vea trabajo infantil ilegal</li><li>Apoyar organizaciones que trabajan por la infancia</li></ul><h3>En la cooperativa</h3><p>Las cooperativas tienen una responsabilidad especial como organizaciones basadas en valores de justicia social. Asegurar que ningún socio ni proveedor emplee menores ilegalmente, y promover activamente los derechos de la niñez.</p><h3>Líneas de denuncia</h3><p>STPS: 800-911-7877 | DIF: 800-888-2323 | SIPINNA: denuncia en línea | PROFEDET: 800-911-7877</p>`, references: ["OIT - Programa IPEC", "UNICEF - Trabajo infantil", "SIPINNA México"], durationMinutes: 15 }
],

// ═══ 5. ATENCIÓN A COMENSALES ═══
"atencion-comensales": [
  { title: "Fundamentos del Servicio al Comensal", description: "Principios de atención, tipos de servicio y comunicación con el cliente", contentHtml: `<h2>El cliente come con todos los sentidos</h2><p>La atención al comensal va más allá de servir platos. Es una <strong>experiencia integral</strong> que incluye la bienvenida, el ambiente, la comunicación, el servicio y el cierre.</p><h3>Principios del servicio</h3><ul><li><strong>Cortesía:</strong> Saludo cálido, contacto visual, sonrisa genuina</li><li><strong>Rapidez:</strong> Atención oportuna sin que el comensal espere excesivamente</li><li><strong>Conocimiento:</strong> Dominar el menú, ingredientes, alérgenos, recomendaciones</li><li><strong>Anticipación:</strong> Detectar necesidades antes de que el comensal las exprese</li><li><strong>Discreción:</strong> Conversaciones privadas del comensal no se comentan</li></ul><h3>Tipos de servicio</h3><ul><li><strong>Americano:</strong> Platos servidos desde cocina. El más común en México</li><li><strong>Francés:</strong> Se presenta la fuente y el comensal se sirve</li><li><strong>Ruso:</strong> El mesero sirve del platón al plato frente al comensal</li><li><strong>Buffet:</strong> El comensal se sirve de una mesa central</li></ul><h3>Comunicación efectiva</h3><p>Lenguaje claro y respetuoso. Tono amable. Escuchar la orden completa antes de interrumpir. Repetir la orden para confirmar. Ofrecer sin presionar.</p>`, references: ["EC0038 - Estándar de competencia CONOCER", "NOM-251-SSA1-2009", "Servicio al cliente - Estándares internacionales"], durationMinutes: 15 },
  { title: "Montaje, Servicio y Protocolo de Mesa", description: "Tipos de montaje, secuencia de servicio y etiqueta básica", contentHtml: `<h2>El montaje cuenta la historia del servicio</h2><h3>Montaje básico de mesa</h3><ul><li>Mantel o individual limpio y sin arrugas</li><li>Plato base centrado al borde de la mesa (2cm del borde)</li><li>Cubiertos: tenedor a la izquierda, cuchillo y cuchara a la derecha</li><li>Copa de agua arriba del cuchillo</li><li>Servilleta doblada sobre el plato o a la izquierda</li></ul><h3>Secuencia del servicio</h3><ol><li><strong>Bienvenida:</strong> Saludo, acompañar a la mesa, presentar carta</li><li><strong>Toma de orden:</strong> Bebidas primero, luego alimentos. Anotar con claridad</li><li><strong>Servicio de bebidas:</strong> Dentro de 3 minutos de la orden</li><li><strong>Servicio de alimentos:</strong> Servir por la derecha, retirar por la derecha. Damas primero</li><li><strong>Seguimiento:</strong> Verificar satisfacción sin ser invasivo</li><li><strong>Postre y café:</strong> Ofrecer al retirar plato principal</li><li><strong>Cuenta:</strong> Presentar cuando el comensal la solicite, en porta-cuenta</li><li><strong>Despedida:</strong> Agradecer la visita, invitar a regresar</li></ol>`, references: ["EC0038 - CONOCER", "Estándares de servicio gastronómico", "Protocolo de atención al cliente"], durationMinutes: 15 },
  { title: "Manejo de Situaciones Difíciles", description: "Quejas, clientes difíciles, alérgenos y emergencias en servicio", contentHtml: `<h2>El problema es una oportunidad</h2><h3>Protocolo ante quejas</h3><ol><li><strong>Escuchar:</strong> Sin interrumpir, sin ponerse a la defensiva</li><li><strong>Empatizar:</strong> "Entiendo su molestia, lamento la situación"</li><li><strong>Actuar:</strong> Ofrecer solución inmediata (cambiar plato, descuento, cortesía)</li><li><strong>Verificar:</strong> Confirmar que el comensal quedó satisfecho</li><li><strong>Reportar:</strong> Informar a la gerencia para prevenir recurrencia</li></ol><h3>Alérgenos alimentarios</h3><p>Los 8 alérgenos principales: leche, huevo, pescado, mariscos, nueces, cacahuate, trigo (gluten), soya. <strong>Siempre preguntar</strong> al comensal sobre alergias o restricciones. Si hay duda, consultar con cocina. Un error con alérgenos puede ser <strong>mortal</strong>.</p><h3>Emergencias</h3><ul><li><strong>Atragantamiento:</strong> Maniobra de Heimlich. Todo el personal debe conocerla</li><li><strong>Reacción alérgica:</strong> Llamar al 911 inmediatamente si hay dificultad para respirar</li><li><strong>Derrame/rotura:</strong> Limpiar inmediatamente, señalizar piso mojado</li></ul>`, references: ["EC0038 - CONOCER", "NOM-251-SSA1-2009", "Cruz Roja - Primeros auxilios"], durationMinutes: 15 },
  { title: "Higiene Personal y Seguridad Alimentaria", description: "Higiene del personal de servicio, manipulación de alimentos y normatividad", contentHtml: `<h2>Limpios por dentro y por fuera</h2><h3>Higiene del personal de servicio</h3><ul><li>Uniforme limpio y planchado cada turno</li><li>Manos limpias — lavarse antes del servicio, después del baño, al tocar dinero</li><li>Uñas cortas y sin esmalte</li><li>Cabello recogido (cofia en cocina, cabello limpio en servicio)</li><li>Sin joyería que pueda caer en alimentos</li><li>No fumar, comer ni mascar chicle durante el servicio</li></ul><h3>Manipulación segura de alimentos en servicio</h3><ul><li>No tocar la comida con las manos — usar pinzas, cucharas, guantes</li><li>No tocar la parte interior de vasos ni copas</li><li>Sujetar cubiertos por el mango, platos por el borde</li><li>Mantener temperaturas: frío ≤4°C, caliente ≥60°C</li><li>No re-servir pan, mantequilla u otros alimentos que regresaron de la mesa</li></ul><h3>NOM-251-SSA1-2009</h3><p>Norma que establece prácticas de higiene para alimentos y bebidas. Todo establecimiento que prepare o sirva alimentos debe cumplirla.</p><h3>Ejercicio</h3><p>Observa el servicio en un restaurante. Identifica 3 cosas que se hacen bien y 3 que podrían mejorar. Aplica lo aprendido.</p>`, references: ["NOM-251-SSA1-2009", "EC0038 - CONOCER", "Codex Alimentarius"], durationMinutes: 15 }
],

// ═══ 6. COMISIONES MIXTAS DE CAPACITACIÓN ═══
"comisiones-mixtas-capacitacion": [
  { title: "Productividad y Capacitación", description: "Relación entre capacitación, productividad y competitividad", contentHtml: `<h2>Capacitar para producir más y mejor</h2><h3>¿Qué es productividad?</h3><p>Es la relación entre los resultados obtenidos y los recursos utilizados. Producir más con menos, o producir mejor con lo mismo. La capacitación es una de las herramientas más efectivas para mejorarla.</p><h3>Medición de la productividad</h3><ul><li><strong>Fórmula básica:</strong> Productividad = Resultados / Recursos</li><li><strong>Indicadores:</strong> Unidades producidas por hora, ventas por empleado, eficiencia de máquinas, defectos por lote</li><li><strong>Línea base:</strong> Medir ANTES de la capacitación para poder comparar DESPUÉS</li></ul><h3>Cómo la capacitación mejora la productividad</h3><ul><li>Reduce errores y reprocesos</li><li>Reduce accidentes y ausentismo</li><li>Mejora la calidad del producto/servicio</li><li>Reduce la rotación de personal</li><li>Aumenta la motivación y compromiso</li></ul><h3>Reparto equitativo de beneficios</h3><p>La LFT establece que los beneficios de la productividad deben <strong>repartirse equitativamente</strong> entre la empresa y los trabajadores. Esto puede ser mediante bonos, mejores condiciones, capacitación adicional o prestaciones.</p>`, references: ["LFT Art. 153-I", "LFT Art. 153-J (Productividad)", "STPS - PROLAB"], durationMinutes: 15 },
  { title: "Integración de la CMCAP", description: "Constitución, miembros, roles y funciones de la Comisión Mixta", contentHtml: `<h2>La comisión que vigila la capacitación</h2><h3>¿Qué es la CMCAP?</h3><p>La Comisión Mixta de Capacitación, Adiestramiento y Productividad es un organismo bipartito obligatorio que supervisa que la capacitación se imparta conforme a la ley.</p><h3>Integración</h3><ul><li>Igual número de representantes del patrón y de los trabajadores</li><li>Los de trabajadores elegidos democráticamente</li><li>El patrón notifica la integración a la STPS</li></ul><h3>Funciones</h3><ul><li>Vigilar la instrumentación del plan de capacitación (DC-1)</li><li>Sugerir medidas para perfeccionar la capacitación</li><li>Emitir opinión sobre los planes de capacitación</li><li>Verificar que los trabajadores reciban sus constancias (DC-3)</li><li>Proponer cambios necesarios al programa</li><li>Denunciar irregularidades</li></ul><h3>Roles específicos</h3><ul><li><strong>Presidente:</strong> Convoca reuniones, coordina actividades</li><li><strong>Secretario:</strong> Levanta actas, lleva registros</li><li><strong>Vocales:</strong> Participan activamente en la vigilancia y propuestas</li></ul>`, references: ["LFT Art. 153-I a 153-K", "Acuerdo STPS - Criterios administrativos", "STPS - Guía de CMCAP"], durationMinutes: 15 },
  { title: "Planes, Programas y Formatos DC", description: "Elaboración del DC-1, emisión del DC-3, y registro del DC-2 y DC-4", contentHtml: `<h2>Los formatos que dan cumplimiento</h2><h3>DC-1: Plan y Programa de Capacitación</h3><p>Documento que presenta: objetivos de capacitación, temas/cursos a impartir, población objetivo, calendario, duración, modalidad, instructor/agente capacitador, y métodos de evaluación.</p><h3>DC-2: Listas de Constancias de Competencias</h3><p>Resumen de todos los DC-3 emitidos en un período. Se registra ante la STPS como evidencia de cumplimiento.</p><h3>DC-3: Constancia de Competencias o Habilidades Laborales</h3><p>El certificado individual que acredita que el trabajador completó y aprobó la capacitación. Datos: nombre del trabajador, CURP, puesto, nombre del curso, duración, fecha, nombre del instructor/ACE, firma del patrón.</p><h3>DC-4: Lista de Trabajadores Capacitados</h3><p>Registro detallado de asistencia con nombres, puestos y firmas.</p><h3>Proceso completo</h3><ol><li>Detectar necesidades (DNC)</li><li>Elaborar DC-1 con la CMCAP</li><li>Ejecutar la capacitación</li><li>Emitir DC-3 a cada trabajador</li><li>Registrar DC-2 y DC-4</li><li>Conservar evidencia por 3+ años</li></ol>`, references: ["STPS - Formatos DC-1 a DC-5", "Acuerdo de criterios administrativos", "LFT Art. 153"], durationMinutes: 15 },
  { title: "Programa de Productividad y Herramientas STPS", description: "Bonos de productividad, PROLAB, FAM y herramientas de apoyo", contentHtml: `<h2>Capacitar es solo el primer paso</h2><h3>Programa de Productividad</h3><p>La CMCAP debe contribuir a diseñar un programa que vincule capacitación con resultados medibles de productividad. Incluye: diagnóstico, indicadores, metas, acciones y esquema de reparto de beneficios.</p><h3>Bonos de productividad</h3><p>Mecanismo para repartir los beneficios del incremento de productividad. Pueden ser: bonos económicos, días de descanso adicionales, capacitación premium, o mejoras en condiciones de trabajo. Deben estar vinculados a indicadores objetivos y medibles.</p><h3>Herramientas STPS</h3><ul><li><strong>PROLAB:</strong> Herramienta de medición y diagnóstico de productividad laboral</li><li><strong>FAM:</strong> Programa de Formación de Agentes Multiplicadores — capacita a personas dentro de la empresa para que capaciten a otros</li><li><strong>PROCADIST:</strong> Cursos gratuitos en línea (como este que estás tomando)</li><li><strong>Ceduverse:</strong> Plataforma con cursos gratuitos + certificación DC3 con valor STPS 🚀</li></ul><h3>Ejercicio final</h3><p>¿Tu centro de trabajo tiene CMCAP? ¿Tiene plan DC-1 vigente? ¿Los trabajadores reciben DC-3? Si alguna respuesta es "no", ahora sabes cómo corregirlo.</p>`, references: ["LFT Art. 153-I a 153-K", "STPS - PROLAB", "STPS - FAM"], durationMinutes: 15 }
],

// ═══ 7. ADMINISTRACIÓN DE LA CAPACITACIÓN PARTE II ═══
"administracion-capacitacion-rh-2": [
  { title: "Detección de Necesidades de Capacitación Avanzada", description: "Métodos profundos de DNC: competencias, desempeño, brechas tecnológicas", contentHtml: `<h2>Más allá de las encuestas</h2><h3>DNC basada en competencias</h3><p>Mapea las competencias requeridas por cada puesto y compáralas con las que tiene el ocupante. La brecha = necesidad de capacitación.</p><h3>DNC por indicadores de negocio</h3><ul><li><strong>Alta rotación:</strong> ¿Falta de desarrollo? ¿Liderazgo deficiente? ¿Clima laboral?</li><li><strong>Quejas de clientes:</strong> ¿Falta de habilidades técnicas o de servicio?</li><li><strong>Accidentes frecuentes:</strong> ¿Falta de capacitación en seguridad?</li><li><strong>Baja productividad:</strong> ¿Falta de conocimiento de procesos o herramientas?</li></ul><h3>DNC por cambios organizacionales</h3><p>Nuevas tecnologías, nuevos procesos, nueva normatividad, fusiones/adquisiciones — todos generan necesidades de capacitación que no se detectan con métodos tradicionales.</p><h3>Priorización de necesidades</h3><ul><li><strong>Urgentes:</strong> Seguridad, cumplimiento legal, problemas críticos</li><li><strong>Importantes:</strong> Desarrollo de competencias clave, productividad</li><li><strong>Deseables:</strong> Crecimiento personal, idiomas, habilidades complementarias</li></ul>`, references: ["Spencer & Spencer - Competence at Work", "STPS - DNC", "Kirkpatrick - Needs Assessment"], durationMinutes: 15 },
  { title: "Diseño Instruccional y Metodologías", description: "Modelo ADDIE, técnicas didácticas y diseño de materiales", contentHtml: `<h2>Diseñar para que aprendan, no para que escuchen</h2><h3>Modelo ADDIE</h3><ol><li><strong>Análisis:</strong> ¿Quién? ¿Qué necesita? ¿En qué contexto?</li><li><strong>Diseño:</strong> Objetivos, estructura, secuencia, evaluación</li><li><strong>Desarrollo:</strong> Crear materiales, ejercicios, evaluaciones</li><li><strong>Implementación:</strong> Impartir, coordinar, facilitar</li><li><strong>Evaluación:</strong> Medir resultados en los 4 niveles de Kirkpatrick</li></ol><h3>Principios de aprendizaje adulto</h3><ul><li>Los adultos necesitan saber el "para qué"</li><li>Aprenden haciendo, no solo escuchando</li><li>Su experiencia es un recurso valioso</li><li>Necesitan aplicación inmediata</li><li>La motivación es más interna que externa</li></ul><h3>Técnicas efectivas</h3><ul><li><strong>Casos de estudio:</strong> Analizar situaciones reales</li><li><strong>Role playing:</strong> Simular situaciones para practicar</li><li><strong>Aprendizaje basado en proyectos:</strong> Resolver un problema real como ejercicio</li><li><strong>Microlearning:</strong> Contenidos breves de 15 min máximo</li></ul>`, references: ["ADDIE Model", "Knowles, M. - Andragogía", "Gagné - Conditions of Learning"], durationMinutes: 15 },
  { title: "Evaluación del Impacto de la Capacitación", description: "Los 4 niveles de Kirkpatrick y cálculo de ROI en capacitación", contentHtml: `<h2>¿Sirvió o solo gastamos?</h2><h3>Modelo de Kirkpatrick — 4 Niveles</h3><ol><li><strong>Reacción (Nivel 1):</strong> ¿Les gustó? → Encuesta de satisfacción al terminar</li><li><strong>Aprendizaje (Nivel 2):</strong> ¿Aprendieron? → Evaluación pre y post (examen, demostración)</li><li><strong>Comportamiento (Nivel 3):</strong> ¿Lo aplican? → Observación en el trabajo después de 30-90 días</li><li><strong>Resultados (Nivel 4):</strong> ¿Impactó al negocio? → Indicadores: productividad, calidad, accidentes, rotación</li></ul><h3>La trampa del Nivel 1</h3><p>La mayoría de las empresas solo evalúa Nivel 1 ("¿te gustó el curso?"). Que les haya gustado no significa que aprendieron, que apliquen, ni que impacte resultados. El valor real está en los Niveles 3 y 4.</p><h3>ROI de la capacitación</h3><p>ROI = (Beneficios - Costos) / Costos × 100</p><p>Ejemplo: Un curso de seguridad costó $50,000 MXN. Después del curso, los accidentes se redujeron y se ahorraron $200,000 en incapacidades. ROI = (200,000 - 50,000) / 50,000 × 100 = <strong>300%</strong></p>`, references: ["Kirkpatrick, D. - Evaluating Training Programs", "Phillips, J. - ROI in Training", "ASTD - Metrics and Reporting"], durationMinutes: 15 },
  { title: "Tendencias y Tecnología en Capacitación", description: "E-learning, IA en capacitación, gamificación y el futuro del aprendizaje laboral", contentHtml: `<h2>La capacitación del futuro ya llegó</h2><h3>Tendencias actuales</h3><ul><li><strong>E-learning y microlearning:</strong> Contenido breve, accesible 24/7 desde cualquier dispositivo</li><li><strong>Gamificación:</strong> Puntos, insignias, rankings que aumentan motivación y retención</li><li><strong>IA en capacitación:</strong> Tutores inteligentes, contenido adaptativo que se ajusta al ritmo del aprendiz</li><li><strong>Realidad virtual:</strong> Simulación de situaciones riesgosas sin peligro real (soldadura, alturas, emergencias)</li><li><strong>Social learning:</strong> Aprendizaje entre pares, comunidades de práctica, mentoring</li><li><strong>Mobile learning:</strong> Contenido optimizado para celular — donde esté tu equipo</li></ul><h3>Blockchain en certificación</h3><p>Plataformas como <strong>Ceduverse</strong> emiten certificados NFT verificables en blockchain. El trabajador tiene control sobre sus credenciales, puede compartirlas con cualquier empleador, y nadie puede falsificarlas.</p><h3>El rol del administrador de capacitación</h3><p>Ya no es solo "organizar cursos". Es un <strong>estratega de talento</strong> que conecta necesidades del negocio con soluciones de aprendizaje, mide resultados, y aprovecha la tecnología para multiplicar el impacto.</p><h3>Ejercicio final</h3><p>Diseña un mini-plan de capacitación anual para tu área: 3 necesidades prioritarias, método de impartición (presencial, en línea, híbrido), y cómo medirías el impacto de cada una.</p>`, references: ["WEF - Future of Jobs 2025", "LinkedIn Learning - Workplace Report", "Ceduverse - Certificación blockchain"], durationMinutes: 15 }
],

// ═══ 8. ORIENTACIÓN Y ASESORÍA JURÍDICA LABORAL ═══
"orientacion-asesoria-juridica-laboral": [
  { title: "La Reforma Laboral y el Nuevo Sistema de Justicia", description: "Cambios clave de la reforma 2019, CFCRL y nuevos tribunales", contentHtml: `<h2>Una nueva era en la justicia laboral</h2><p>La Reforma Laboral de 2019 transformó el sistema de justicia laboral en México, creando nuevas instituciones y procedimientos para resolver conflictos de manera más justa, rápida y transparente.</p><h3>Cambios principales</h3><ul><li>Desaparecen las Juntas de Conciliación y Arbitraje</li><li>Se crean <strong>Tribunales Laborales</strong> del Poder Judicial (independientes)</li><li>Se crea el <strong>Centro Federal de Conciliación y Registro Laboral (CFCRL)</strong></li><li>La conciliación es <strong>obligatoria antes del juicio</strong> (prejudicial)</li><li>Voto personal, libre, directo y secreto en sindicatos</li><li>Legitimación de contratos colectivos por voto de trabajadores</li></ul><h3>El proceso actual</h3><ol><li><strong>Conciliación prejudicial:</strong> En el CFCRL — obligatoria, máximo 45 días</li><li><strong>Si no hay acuerdo:</strong> El trabajador presenta demanda ante el Tribunal Laboral</li><li><strong>Juicio:</strong> Proceso oral, rápido, con juez independiente</li></ol><h3>¿A dónde ir?</h3><ul><li><strong>PROFEDET:</strong> Asesoría legal gratuita para trabajadores (800-911-7877)</li><li><strong>CFCRL:</strong> Conciliación obligatoria</li><li><strong>Tribunales Laborales:</strong> Si la conciliación no funciona</li></ul>`, references: ["Reforma LFT 2019", "CFCRL - Centro Federal de Conciliación", "PROFEDET"], durationMinutes: 15 },
  { title: "Derechos Fundamentales en el Trabajo", description: "Derechos individuales y colectivos que todo asesor debe conocer", contentHtml: `<h2>Conocer para defender</h2><h3>Derechos individuales clave</h3><ul><li><strong>Contrato escrito:</strong> Obligatorio. Sin contrato, se presumen ciertas las condiciones que declare el trabajador</li><li><strong>Salario mínimo:</strong> Irrenunciable. No puede pactarse por debajo</li><li><strong>Jornada máxima:</strong> 8 horas diurna. Horas extras pagadas al 200% (primeras 9/semana) y 300% (excedentes)</li><li><strong>Prestaciones de ley:</strong> Aguinaldo (15 días min.), vacaciones (12 días min. primer año), prima vacacional (25%), seguro social, PTU</li><li><strong>Estabilidad en el empleo:</strong> Solo se puede despedir por causa justificada (LFT Art. 47)</li><li><strong>Indemnización:</strong> 3 meses + 20 días/año si el despido es injustificado</li></ul><h3>Derechos colectivos</h3><ul><li>Libertad sindical: derecho a formar sindicatos y afiliarse</li><li>Contratación colectiva: negociar condiciones como grupo</li><li>Huelga: derecho constitucional como último recurso</li></ul><h3>Derechos de grupos vulnerables</h3><p>Protección especial contra discriminación por género, edad, discapacidad, embarazo, orientación sexual, origen étnico. La LFT Art. 3 prohíbe toda forma de discriminación laboral.</p>`, references: ["LFT - Título Cuarto", "Constitución Art. 123", "OIT - Convenios fundamentales"], durationMinutes: 15 },
  { title: "Proceso de Conciliación y Asesoría", description: "Cómo funciona la conciliación prejudicial y el rol del asesor", contentHtml: `<h2>Primero intentar el acuerdo</h2><h3>Conciliación prejudicial (CFCRL)</h3><p>Antes de iniciar un juicio laboral, es <strong>obligatorio</strong> intentar una conciliación en el CFCRL. Excepciones: discriminación, hostigamiento sexual, y trabajadores del hogar.</p><h3>El proceso</h3><ol><li><strong>Solicitud:</strong> El trabajador o su asesor presentan solicitud ante el CFCRL</li><li><strong>Citación:</strong> Se cita al patrón a la audiencia de conciliación</li><li><strong>Audiencia:</strong> Conciliador facilita el diálogo entre las partes</li><li><strong>Acuerdo:</strong> Si hay acuerdo, se firma y tiene fuerza de sentencia</li><li><strong>No acuerdo:</strong> Se emite constancia de no conciliación y se puede ir a juicio</li></ol><h3>Plazo</h3><p>La conciliación no puede durar más de <strong>45 días naturales</strong>.</p><h3>Rol del asesor</h3><ul><li>Orientar al trabajador sobre sus derechos y opciones</li><li>Calcular las cantidades que le corresponden</li><li>Prepararlo para la audiencia</li><li>Acompañarlo durante el proceso</li><li>Asegurar que cualquier acuerdo respete sus derechos mínimos</li></ul>`, references: ["LFT Art. 684-A a 684-E (Conciliación)", "CFCRL - Procedimiento", "PROFEDET - Asesoría"], durationMinutes: 15 },
  { title: "Cálculos Laborales Básicos y Recursos", description: "Cómo calcular finiquito, liquidación, y recursos de defensa", contentHtml: `<h2>Los números no mienten</h2><h3>Finiquito (renuncia voluntaria)</h3><ul><li>Días trabajados no pagados</li><li>Parte proporcional de aguinaldo</li><li>Parte proporcional de vacaciones y prima vacacional</li><li>Prima de antigüedad (12 días/año si tiene 15+ años)</li></ul><h3>Liquidación (despido injustificado)</h3><ul><li>Todo lo del finiquito +</li><li><strong>3 meses de salario</strong> (indemnización constitucional)</li><li><strong>20 días por año trabajado</strong> (Art. 50 LFT)</li><li>Prima de antigüedad (12 días/año, tope 2 salarios mínimos)</li><li>Salarios vencidos (si hay juicio, desde el despido hasta la sentencia, tope 12 meses)</li></ul><h3>¿Dónde buscar ayuda?</h3><ul><li><strong>PROFEDET:</strong> Asesoría y representación legal gratuita. 800-911-7877</li><li><strong>CFCRL:</strong> Conciliación obligatoria. cfcrl.gob.mx</li><li><strong>Procuradurías locales de defensa del trabajo</strong></li><li><strong>Organizaciones de la sociedad civil</strong> especializadas en derechos laborales</li></ul><h3>Ejercicio</h3><p>Un trabajador con 3 años de antigüedad y salario de $500/día es despedido injustificadamente. Calcula su liquidación aproximada. (Pista: 3 meses + 20 días × 3 años + proporcionales + prima de antigüedad)</p>`, references: ["LFT Art. 48, 50, 89, 162", "PROFEDET - Calculadora laboral", "CFCRL - Guía del usuario"], durationMinutes: 15 }
]

};

